+        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="RetryAsync">Retry</button>
+    </div>
+}
+else if (_recipes is null)
+{
+    <div class="d-flex align-items-center gap-2 my-4">
+        <div class="spinner-border text-primary" role="status"></div>
+        <span>Loading recipes…</span>
+    </div>
+}
+else
+{
+    @if (_isRefreshing)
+    {
+        <div class="alert alert-info py-1 px-2 d-inline-flex align-items-center gap-2 mb-3" role="status">
+            <div class="spinner-border spinner-border-sm"></div>
+            <span>Refreshing…</span>
+        </div>
+    }
+
+    <div class="mb-3">
+        <label class="form-label fw-semibold">Sort by:</label>
+        <a href="@GetSortUrl("newest")" class="btn btn-sm @(CurrentSort == "newest" ? "btn-primary" : "btn-outline-secondary") me-1">Newest</a>
+        <a href="@GetSortUrl("popular")" class="btn btn-sm @(CurrentSort == "popular" ? "btn-primary" : "btn-outline-secondary")">Popular</a>
+    </div>
+
+    @if (_recipes.Count == 0)
+    {
+        <p class="text-muted">No recipes found for this cuisine.</p>
+    }
+    else
+    {
+        <div class="row row-cols-1 row-cols-md-3 g-3">
+            @foreach (var recipe in GetSortedRecipes())
+            {
+                <div class="col">
+                    <div class="card h-100">
+                        <div class="card-body">
+                            <h5 class="card-title">@recipe.Title</h5>
+                            <p class="card-text">@recipe.Description</p>
+                        </div>
+                        <div class="card-footer text-muted">
+                            🕐 @recipe.PrepTimeMinutes min
+                        </div>
+                    </div>
+                </div>
+            }
+        </div>
+    }
+}
+
+@code {
+    [Parameter] public int CuisineId { get; set; }
+    [SupplyParameterFromQuery(Name = "sort")] public string? Sort { get; set; }
+
+    private List<Recipe>? _recipes;
+    private string? _errorMessage;
+    private bool _isRefreshing;
+    private int _loadedCuisineId;
+    private CancellationTokenSource? _cts;
+
+    private string CurrentSort => string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase) ? "popular" : "newest";
+
+    protected override async Task OnParametersSetAsync()
+    {
+        if (CuisineId == _loadedCuisineId && _recipes is not null)
+        {
+            // Only sort changed — no data reload needed.
+            return;
+        }
+
+        await LoadRecipesAsync();
+    }
+
+    private async Task LoadRecipesAsync()
+    {
+        // Cancel any in-flight request for a previous cuisine.
+        await CancelPendingRequestAsync();
+
+        _errorMessage = null;
+        _isRefreshing = _recipes is not null;
+
+        if (!_isRefreshing)
+        {
+            StateHasChanged();
+        }
+
+        var cts = new CancellationTokenSource(TimeSpan.FromSeconds(15));
+        _cts = cts;
+
+        try
+        {
+            var results = await RecipeService.GetByCuisineAsync(CuisineId, cts.Token);
+
+            // Guard against a stale response arriving after a newer request was started.
+            if (cts.Token.IsCancellationRequested)
+                return;
+
+            _recipes = results;
+            _loadedCuisineId = CuisineId;
+            _errorMessage = null;
+        }
+        catch (OperationCanceledException) when (cts.Token.IsCancellationRequested)
+        {
+            // Expected when navigating away or switching cuisines — nothing to do.
+        }
+        catch (TimeoutException ex)
+        {
+            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
+            _errorMessage = "The request timed out. Please try again.";
+        }
+        catch (Exception ex)
+        {
+            Logger.LogError(ex, "Failed to load recipes for cuisine {CuisineId}", CuisineId);
+            _errorMessage = "Something went wrong while loading recipes. Please try again.";
+        }
+        finally
+        {
+            _isRefreshing = false;
+        }
+    }
+
+    private async Task RetryAsync()
+    {
+        await LoadRecipesAsync();
+    }
+
+    private List<Recipe> GetSortedRecipes()
+    {
+        if (_recipes is null) return new();
+
+        return CurrentSort == "popular"
+            ? _recipes.OrderBy(r => r.PrepTimeMinutes).ToList()
+            : _recipes.OrderByDescending(r => r.Id).ToList();
+    }
+
+    private string GetSortUrl(string sort)
+    {
+        return $"/recipes/{CuisineId}?sort={sort}";
+    }
+
+    private async Task CancelPendingRequestAsync()
+    {
+        if (_cts is not null)
+        {
+            await _cts.CancelAsync();
+            _cts.Dispose();
+            _cts = null;
+        }
+    }
+
+    public void Dispose()
+    {
+        _cts?.Cancel();
+        _cts?.Dispose();
+        _cts = null;
+    }
+}
+

